'use strict';

const languageCore = require('@vue/language-core');
const typescript = require('@volar/typescript');
const plugin = require('../shared/unplugin-dts.BSDVFQ9C.cjs');
const ts = require('./ts.cjs');
require('node:path');
require('node:fs');
require('node:module');
require('kolorist');
require('node:fs/promises');
require('node:os');
require('@rollup/pluginutils');
require('compare-versions');
require('debug');
require('local-pkg');
require('magic-string');

const createProgram = typescript.proxyCreateProgram(plugin.ts, plugin.ts.createProgram, (ts2, options) => {
  const { configFilePath } = options.options;
  const vueOptions = typeof configFilePath === "string" ? languageCore.createParsedCommandLine(ts2, ts2.sys, plugin.slash(configFilePath)).vueOptions : languageCore.getDefaultCompilerOptions();
  const vueLanguagePlugin = languageCore.createVueLanguagePlugin(
    ts2,
    options.options,
    vueOptions,
    (id) => id
  );
  return { languagePlugins: [vueLanguagePlugin] };
});

exports.createParsedCommandLine = ts.createParsedCommandLine;
exports.createProgram = createProgram;
